const tz = 'Asia/Riyadh';
const now  = new Date(new Date().toLocaleString('en-US',{timeZone:tz}));
const yest = new Date(now); yest.setDate(now.getDate()-1);
const fmt  = d => d.toISOString().slice(0,10);
const ago  = n => { const d=new Date(now); d.setDate(now.getDate()-n); return fmt(d); };
return [{ json:{
  today:     fmt(now),
  yesterday: fmt(yest),
  start_7d:  ago(7),
  start_14d: ago(14),
  start_30d: ago(30),
  ts_7d_ms:  String(new Date(ago(7)).getTime()),
}}];

const rows  = $input.all().map(i => i.json);
const today = $('Set Dates').first().json.yesterday;
const summary = rows.reduce((acc, r) => {
  acc[r.channel] = acc[r.channel] || { spend:0, impressions:0, conversions:0, rows:0 };
  acc[r.channel].spend       += r.spend || 0;
  acc[r.channel].impressions += r.impressions || 0;
  acc[r.channel].conversions += r.conversions || 0;
  acc[r.channel].rows++;
  return acc;
}, {});

const report = Object.entries(summary).map(([ch, s]) =>
  `${ch}: ${s.rows} rows, $${s.spend.toFixed(2)} spend, ${s.impressions} impressions`
).join('\n');

return [{ json: {
  system: `You are a data quality guard for a paid media system. Flag corrupt, zero-spend, or suspiciously low data.`,
  messages: [{
    role: 'user',
    content: `Date: ${today}\nData summary:\n${report}\n\nValidate this data. Use the report_guard tool.`
  }],
  tools: [{
    name: 'report_guard',
    description: 'Report data quality verdict',
    input_schema: {
      type: 'object',
      properties: {
        should_load: { type: 'boolean', description: 'true if data looks valid' },
        reason:      { type: 'string',  description: 'One sentence explanation' },
        flags:       { type: 'array', items: { type: 'string' }, description: 'channels with issues' }
      },
      required: ['should_load','reason']
    }
  }],
  rows,
}}];

const resp = $input.first().json;
const block = (resp.content||[]).find(b => b.type==='tool_use' && b.name==='report_guard');
if (!block) return [{ json: { should_load: false, reason: 'guard_no_tool_use', flags:[] }}];
return [{ json: block.input }];

// Compare BQ lead counts to HubSpot API response
const bqRows  = $('Query BQ Recon').all().map(i=>i.json);
const hsTotal = ($('Query HS Recon').first().json?.results||[]).length || 0;
const bqTotal = bqRows.reduce((s,r)=>s+(r.bq_leads||0), 0);

const delta = bqTotal > 0 ? Math.abs(bqTotal - hsTotal) / bqTotal : 0;
const ok    = delta <= 0.02; // 2% tolerance

return [{ json: {
  recon_ok:      ok,
  bq_total:      bqTotal,
  hs_total:      hsTotal,
  delta_pct:     Math.round(delta*100*10)/10,
  channel_breakdown: bqRows,
  alert_msg: ok ? null :
    `BQ?HubSpot gap: BQ=${bqTotal} HS=${hsTotal} (${Math.round(delta*100)}% delta) - exceeds 2% threshold`
}}];

const kpis    = $('Query KPIs').all().map(i=>i.json);
const period  = $('Query Period Compare').all().map(i=>i.json);
const monitor = $('Query Monitor').all().map(i=>i.json);
const date    = $('Set Dates').first().json.yesterday;

// Period delta calculation
const by_channel = {};
for (const r of period) {
  by_channel[r.channel] = by_channel[r.channel] || {};
  by_channel[r.channel][r.period] = r;
}
const deltas = Object.entries(by_channel).map(([ch, p]) => {
  const a = p.A_prior, b = p.B_this;
  if (!a || !b) return null;
  const dcpql = a.cpql > 0 ? Math.round((b.cpql - a.cpql)/a.cpql*100) : 0;
  const flag  = b.cpql < 85 ? 'GREEN' : b.cpql < 130 ? 'AMBER' : 'RED';
  return { channel:ch, cpql_now:b.cpql, cpql_prior:a.cpql, dcpql_pct:dcpql,
           leads_now:b.leads, leads_prior:a.leads, spend_now:b.spend, flag };
}).filter(Boolean);

const payload_text = [
  `Date: ${date}`,
  `KPIs (yesterday): ${JSON.stringify(kpis)}`,
  `7d vs prior 7d: ${JSON.stringify(deltas)}`,
  `Pending monitor (7d/14d due): ${JSON.stringify(monitor)}`
].join('\n\n');

return [{ json: {
  system: $('Config � Flatten').first().json.growth_analyst_role + '\n\n---\n\n' + $('Config � Flatten').first().json.kpi_rules + '\n\n---\n\n' + $('Config � Flatten').first().json.attribution_rules,
  messages: [{ role:'user', content: payload_text }],
  tools: [{
    name: 'growth_analyst_report',
    description: 'Structured period comparison output',
    input_schema: {
      type: 'object',
      properties: {
        channel_flags: { type:'array', items:{ type:'object',
          properties:{ channel:{type:'string'}, flag:{type:'string'}, cpql_now:{type:'number'},
                       cpql_delta_pct:{type:'number'}, root_cause:{type:'string'} }}},
        red_channels:  { type:'array', items:{type:'string'} },
        monitor_updates: { type:'array', items:{ type:'object' }},
        summary_one_liner: { type:'string' }
      },
      required:['channel_flags','red_channels','summary_one_liner']
    }
  }]
}}];

const resp  = $input.first().json;
const block = (resp.content||[]).find(b=>b.type==='tool_use'&&b.name==='growth_analyst_report');
return [{ json: block ? block.input : { channel_flags:[], red_channels:[], summary_one_liner:'parse error' }}];

const ga   = $('Parse � growth-analyst').first().json;
const audit= $('Query Ad Audit').all().map(i=>i.json);
const date = $('Set Dates').first().json.yesterday;
const pausable = audit.filter(a=>['PAUSE_ZERO_CONV','PAUSE_JUNK','PAUSE_HIGH_CPL'].includes(a.recommendation));
const scalable  = audit.filter(a=>a.recommendation==='SCALE');

const payload = [
  `Date: ${date}`,
  `Red channels: ${JSON.stringify(ga.red_channels)}`,
  `Channel flags: ${JSON.stringify(ga.channel_flags)}`,
  `Ads to pause (${pausable.length}): ${JSON.stringify(pausable.slice(0,20))}`,
  `Ads to scale (${scalable.length}): ${JSON.stringify(scalable.slice(0,10))}`,
].join('\n\n');

return [{ json: {
  system: $('Config � Flatten').first().json.performance_lead_role + '\n\n---\n\n' + $('Config � Flatten').first().json.kpi_rules,
  messages: [{ role:'user', content: payload }],
  tools: [{
    name: 'perf_lead_decision',
    description: 'Structured pause/scale/investigate decisions',
    input_schema: {
      type: 'object',
      properties: {
        pause_items: { type:'array', items:{ type:'object',
          properties:{ campaign_name:{type:'string'}, ad_name:{type:'string'},
                       channel:{type:'string'}, reason:{type:'string'},
                       spend_14d:{type:'number'}, cpql:{type:'number'}, days_active:{type:'number'}}}},
        scale_items: { type:'array', items:{ type:'object',
          properties:{ campaign_name:{type:'string'}, channel:{type:'string'},
                       budget_current:{type:'number'}, budget_proposed:{type:'number'},
                       cpql_14d:{type:'number'}, leads_14d:{type:'number'}}}},
        investigate_items: { type:'array', items:{ type:'object' }},
        needs_new_campaign: { type:'boolean' }
      },
      required:['pause_items','scale_items','investigate_items']
    }
  }]
}}];

const resp  = $input.first().json;
const block = (resp.content||[]).find(b=>b.type==='tool_use'&&b.name==='perf_lead_decision');
return [{ json: block ? block.input : { pause_items:[], scale_items:[], investigate_items:[], needs_new_campaign:false }}];

const ga    = $('Parse � growth-analyst').first().json;
const pl    = $('Parse � performance-lead').first().json;
const fc    = $('Query Forecast').all().map(i=>i.json);
const mon   = $('Query Monitor').all().map(i=>i.json);
const date  = $('Set Dates').first().json.yesterday;
const d7    = $('Set Dates').first().json.start_7d;

const pause_lines  = (pl.pause_items||[]).map(p=>
  `?  \`${p.campaign_name}\` - ${p.ad_name} (${p.channel}) | ${p.days_active}d | $${p.spend_14d} | ${p.reason}`
).join('\n');

const scale_lines  = (pl.scale_items||[]).map(s=>
  `?  \`${s.campaign_name}\` (${s.channel}) | $${s.budget_current}/d ? $${s.budget_proposed}/d | CPQL $${s.cpql_14d} | ${s.leads_14d} leads`
).join('\n');

const invest_lines = (pl.investigate_items||[]).map((v,i)=>
  `?  ${JSON.stringify(v)}`
).join('\n');

const flag_lines   = (ga.channel_flags||[]).map(f=>
  `${f.flag==='GREEN'?'?':f.flag==='AMBER'?'??':'??'}  ${f.channel}  CPQL $${f.cpql_now} (${f.cpql_delta_pct>0?'+':''}${f.cpql_delta_pct}%)`
).join('\n');

const fc_lines     = fc.map(r=>
  `. ${r.channel}: ~$${r.proj_spend?.toLocaleString()} spend | ${r.proj_leads} leads | ${r.proj_sqls} SQLs | CPQL $${r.cpql_7d}`
).join('\n');

const mon_lines    = mon.length ? mon.map(m=>
  `??  ${m.action_type} on \`${m.target_name}\` (${m.channel}) - ${m.days_since}d ago`
).join('\n') : '_No actions due for review._';

const asana_count = (pl.pause_items||[]).length + (pl.scale_items||[]).length + (pl.investigate_items||[]).length;

const digest = `Nexa � ${date}  |  <https://nexa-web-production-6a6b.up.railway.app/activity|activity dashboard>

PERFORMANCE  (${d7} ? ${date} vs prior 7d)
${flag_lines || '(no channel data)'}

ACTIONS  -  ? executes all  �  ? skips all
${scale_lines || '(no scale candidates)'}
${pause_lines || '(no pause candidates)'}

REVIEW ONLY  (Asana tasks created - no execution needed)
${invest_lines || '(none)'}

MONITOR
${mon_lines}

FORECAST  (7d run rate � 4.3)
${fc_lines || '(no forecast data)'}

Asana open tasks: ${asana_count}`;

return [{ json: {
  digest,
  pause_items:    pl.pause_items    || [],
  scale_items:    pl.scale_items    || [],
  investigate_items: pl.investigate_items || [],
  has_actions: (pl.pause_items||[]).length+(pl.scale_items||[]).length > 0,
  asana_tasks: (pl.investigate_items||[]).concat(
    (pl.pause_items||[]).map(p=>({...p, task_type:'PAUSE_CANDIDATE'})),
    (pl.scale_items||[]).map(s=>({...s, task_type:'SCALE_CANDIDATE'}))
  ).map(t=>(({
    data: {
      name: `[${t.task_type||'FLAG'}] ${t.campaign_name||t.channel||'item'} - ${new Date().toISOString().slice(0,10)}`,
      notes: `${JSON.stringify(t)}\n\nCreated: ${new Date().toISOString().slice(0,10)}\nPriority: High\nChannel: ${t.channel||''}`,
      projects: ['1214135581886045'],
      assignee: '1208007704598388',
      due_on: new Date(Date.now()+2*86400000).toISOString().slice(0,10)
    }
  })))
}}];

const row = {
  date:       $('Set Dates').first().json.yesterday,
  action_type:'daily_loop',
  target_name:'n8n_workflow',
  target_id:  'T8icImtZFLYeCa7e',
  channel:    'all',
  event_date: new Date().toISOString().slice(0,10),
  outcome:    'completed',
  notes:      `guard_passed=true recon_ok=${$('Reconcile BQ vs HS').first().json.recon_ok} bq_total=${$('Reconcile BQ vs HS').first().json.bq_total}`
};
const vals = `STRUCT(
  DATE('${row.date}') AS date,
  '${row.action_type}' AS action_type,
  '${row.target_name}' AS target_name,
  '${row.target_id}' AS target_id,
  '${row.channel}' AS channel,
  DATE('${row.event_date}') AS event_date,
  '${row.outcome}' AS outcome,
  '${row.notes}' AS notes
)`;
return [{ json: { sql: `INSERT INTO \`${$vars.BQ_PROJECT}.${$vars.BQ_DATASET}.agent_activity_log\`
  (date,action_type,target_name,target_id,channel,event_date,outcome,notes)
  SELECT * FROM UNNEST([${vals}])` } }];

const pl = $('Parse � performance-lead').first().json;
const ga = $('Parse � growth-analyst').first().json;
const date = $('Set Dates').first().json.yesterday;

const context = [
  `Date: ${date}`,
  `Red channels: ${JSON.stringify(ga.red_channels||[])}`,
  `Scale items needing new campaigns: ${JSON.stringify(pl.scale_items||[])}`,
  `Investigate items: ${JSON.stringify(pl.investigate_items||[])}`,
].join('\n\n');

return [{ json: {
  system: $('Config � Flatten').first().json.campaign_manager_role + '\n\n---\n\n' + $('Config � Flatten').first().json.kpi_rules,
  messages: [{ role: 'user', content: `Performance lead has flagged needs_new_campaign. Review context and spec the new campaign builds.\n\n${context}` }],
  tools: [{
    name: 'campaign_manager_output',
    description: 'Structured campaign build specs',
    input_schema: {
      type: 'object',
      properties: {
        campaign_builds: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              campaign_name: { type: 'string' },
              channel:       { type: 'string' },
              objective:     { type: 'string' },
              daily_budget:  { type: 'number' },
              audience:      { type: 'string' },
              product:       { type: 'string' },
              lp_url:        { type: 'string' },
              pixel_events:  { type: 'array', items: { type: 'string' } },
              notes:         { type: 'string' }
            }
          }
        },
        naming_violations: { type: 'array', items: { type: 'string' } }
      },
      required: ['campaign_builds']
    }
  }]
}}];

const resp  = $input.first().json;
const block = (resp.content||[]).find(b=>b.type==='tool_use'&&b.name==='campaign_manager_output');
return [{ json: block ? { ...block.input, agent: 'campaign-manager' } : { campaign_builds:[], agent:'campaign-manager' }}];

const pl  = $('Parse � performance-lead').first().json;
const ga  = $('Parse � growth-analyst').first().json;
const date = $('Set Dates').first().json.yesterday;

const context = [
  `Date: ${date}`,
  `Red channels: ${JSON.stringify(ga.red_channels||[])}`,
  `Channel flags: ${JSON.stringify(ga.channel_flags||[])}`,
  `Scale items: ${JSON.stringify(pl.scale_items||[])}`,
].join('\n\n');

return [{ json: {
  system: $('Config � Flatten').first().json.creative_strategist_role + '\n\n---\n\n' + $('Config � Flatten').first().json.kpi_rules + '\n\n---\n\n' + $('Config � Flatten').first().json.brand_playbook,
  messages: [{ role: 'user', content: `Review performance context and define creative variants for flagged channels.\n\n${context}` }],
  tools: [{
    name: 'creative_strategist_output',
    description: 'Structured creative strategy output',
    input_schema: {
      type: 'object',
      properties: {
        creative_variants: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              channel:       { type: 'string' },
              persona:       { type: 'string' },
              variant_label: { type: 'string' },
              headline:      { type: 'string' },
              primary_text:  { type: 'string' },
              cta:           { type: 'string' },
              lp_alignment:  { type: 'string' },
              ab_hypothesis: { type: 'string' }
            }
          }
        },
        ab_test_plan: { type: 'string' }
      },
      required: ['creative_variants']
    }
  }]
}}];

const resp  = $input.first().json;
const block = (resp.content||[]).find(b=>b.type==='tool_use'&&b.name==='creative_strategist_output');
return [{ json: block ? { ...block.input, agent: 'creative-strategist' } : { creative_variants:[], agent:'creative-strategist' }}];

const yesterday = $('Set Dates').first().json.yesterday;
const proj = $vars.BQ_PROJECT;
const ds   = $vars.BQ_DATASET;
const results = [];

// ?? AD CHANNELS ? campaigns_daily ???????????????????????????????
const adMaps = [
  'Map � Google Ads',
  'Map � Meta',
  'Map � Snapchat',
  'Map � TikTok',
  'Map � LinkedIn',
  'Map � Microsoft Ads',
];

for (const mapNode of adMaps) {
  const rows = $(mapNode).all().map(i => i.json);
  if (!rows.length) continue;
  const vals = rows.map(r => `STRUCT(
  DATE('${(r.date||yesterday).replace(/'/g,"''")}') AS date,
  '${(r.channel||'').replace(/'/g,"''")}' AS channel,
  '${String(r.campaign_id||'').replace(/'/g,"''")}' AS campaign_id,
  '${String(r.campaign_name||'').replace(/'/g,"''")}' AS campaign_name,
  ${r.impressions||0} AS impressions,
  ${r.clicks||0} AS clicks,
  ${Number(r.spend||0).toFixed(6)} AS spend,
  ${r.conversions||0} AS conversions
)`).join(',\n');
  const sql = `MERGE \`${proj}.${ds}.campaigns_daily\` AS T
USING (SELECT * FROM UNNEST([${vals}])) AS S
ON T.date=S.date AND T.channel=S.channel AND T.campaign_id=S.campaign_id
WHEN MATCHED THEN UPDATE SET
  campaign_name=S.campaign_name, impressions=S.impressions,
  clicks=S.clicks, spend=S.spend, conversions=S.conversions,
  updated_at=CURRENT_TIMESTAMP()
WHEN NOT MATCHED THEN INSERT
  (date,channel,campaign_id,campaign_name,impressions,clicks,spend,conversions,created_at,updated_at)
VALUES(S.date,S.channel,S.campaign_id,S.campaign_name,S.impressions,S.clicks,S.spend,S.conversions,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP())`;
  results.push({ json: { channel: rows[0]?.channel || mapNode, sql } });
}

// ?? HUBSPOT ? hubspot_leads_module_daily (aggregated) ????????????
// Contacts arrive as individual rows - aggregate to daily counts first
const hsRaw = $('Map � HubSpot').all().map(i => i.json);
if (hsRaw.length) {
  const agg = {};
  for (const r of hsRaw) {
    const date = (r.createdate || yesterday).slice(0,10);
    const camp = String(r.lead_utm_campaign||'').replace(/'/g,"''");
    const key  = date + '__' + camp;
    if (!agg[key]) agg[key] = { date, lead_utm_campaign: camp, leads_total: 0, leads_qualified: 0, leads_disqualified: 0 };
    agg[key].leads_total++;
    const st = (r.lead_status||'').toLowerCase();
    if (['sql','mql','qualified','sales qualified lead'].includes(st)) agg[key].leads_qualified++;
    if (['disqualified','junk','unqualified'].includes(st)) agg[key].leads_disqualified++;
  }
  const rows = Object.values(agg);
  const vals = rows.map(r => `STRUCT(
  DATE('${r.date}') AS date,
  '${r.lead_utm_campaign}' AS lead_utm_campaign,
  ${r.leads_total} AS leads_total,
  ${r.leads_qualified} AS leads_qualified,
  ${r.leads_disqualified} AS leads_disqualified
)`).join(',\n');
  const sql = `MERGE \`${proj}.${ds}.hubspot_leads_module_daily\` AS T
USING (SELECT * FROM UNNEST([${vals}])) AS S
ON T.date=S.date AND T.lead_utm_campaign=S.lead_utm_campaign
WHEN MATCHED THEN UPDATE SET
  leads_total=S.leads_total, leads_qualified=S.leads_qualified,
  leads_disqualified=S.leads_disqualified, updated_at=CURRENT_TIMESTAMP()
WHEN NOT MATCHED THEN INSERT
  (date,lead_utm_campaign,leads_total,leads_qualified,leads_disqualified,created_at,updated_at)
VALUES(S.date,S.lead_utm_campaign,S.leads_total,S.leads_qualified,S.leads_disqualified,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP())`;
  results.push({ json: { channel: 'hubspot', sql } });
}

return results;

const kpis = $('Query KPIs').all().map(i => i.json);
const flags = [];
const today = new Date().toISOString().slice(0, 10);

for (const row of kpis) {
  const { channel, roas, cpql, cpl, qual_pct, spend, leads } = row;
  if (!spend || spend < 5) continue; // skip channels with tiny spend

  // ROAS < 1x ? 3-factor check (Sub-Flow A)
  if (roas !== null && roas < 1.0) {
    flags.push({ flag_type: 'roas', channel, roas, cpql: cpql||0,
                 qual_rate_pct: qual_pct||0, leads_total: leads||0,
                 prior_leads_total: leads||0, spend, date: today });
  }

  // CPQL > $60 (above scale target) ? Sub-Flow C
  if (cpql !== null && cpql > 60 && (leads||0) >= 3) {
    flags.push({ flag_type: 'cpql', channel, cpql, cpl: cpl||0,
                 qual_rate_pct: qual_pct||0, leads, spend, date: today });
  }

  // CPL > $25 (above scale target) ? Sub-Flow B
  if (cpl !== null && cpl > 25 && (leads||0) >= 3) {
    flags.push({ flag_type: 'cpl', channel, cpl, leads, spend, date: today });
  }

  // Qual rate < 45% ? Sub-Flow D
  if (qual_pct !== null && qual_pct < 45 && (leads||0) >= 5) {
    flags.push({ flag_type: 'qual', channel, qual_rate_pct: qual_pct,
                 cpql: cpql||0, leads, spend, date: today });
  }
}

if (flags.length === 0) {
  return [{ json: { flag_type: 'green',
                    message: 'ALL SYSTEMS GREEN - no KPI flags today',
                    date: today } }];
}

console.log(`KPI Evaluator: ${flags.length} flag(s) found`);
return flags.map(f => ({ json: f }));

