const rows = $('BQ � Fetch Config').all().map(i => i.json);
const config = {};
for (const r of rows) { config[r.key] = r.value; }
// Merge date fields so sub-workflow trigger receives yesterday, start_7d etc.
const dates = $('Set Dates').first().json;
return [{ json: { ...config, ...dates } }];

const tz = 'Asia/Riyadh';
const now  = new Date(new Date().toLocaleString('en-US',{timeZone:tz}));
const yest = new Date(now); yest.setDate(now.getDate()-1);
const fmt  = d => d.toISOString().slice(0,10);
const ago  = n => { const d=new Date(now); d.setDate(now.getDate()-n); return fmt(d); };
return [{ json:{
  today:     fmt(now),
  yesterday: fmt(yest),
  start_7d:  ago(7),
  start_14d: ago(14),
  start_30d: ago(30),
  ts_7d_ms:  String(new Date(ago(7)).getTime()),
}}];

const rows  = $input.all().map(i => i.json);
const today = $('Set Dates').first().json.yesterday;
const summary = rows.reduce((acc, r) => {
  acc[r.channel] = acc[r.channel] || { spend:0, impressions:0, conversions:0, rows:0 };
  acc[r.channel].spend       += r.spend || 0;
  acc[r.channel].impressions += r.impressions || 0;
  acc[r.channel].conversions += r.conversions || 0;
  acc[r.channel].rows++;
  return acc;
}, {});

const report = Object.entries(summary).map(([ch, s]) =>
  `${ch}: ${s.rows} rows, $${s.spend.toFixed(2)} spend, ${s.impressions} impressions`
).join('\n');

return [{ json: {
  system: `You are a data quality guard for a paid media system. Flag corrupt, zero-spend, or suspiciously low data.`,
  messages: [{
    role: 'user',
    content: `Date: ${today}\nData summary:\n${report}\n\nValidate this data. Use the report_guard tool.`
  }],
  tools: [{
