const adMaps = [
  'Map � Google Ads',
  'Map � Meta',
  'Map � Snapchat',
  'Map � TikTok',
  'Map � LinkedIn',
  'Map � Microsoft Ads',
];

for (const mapNode of adMaps) {
  const rows = $(mapNode).all().map(i => i.json);
  if (!rows.length) continue;
  const vals = rows.map(r => `STRUCT(
  DATE('${(r.date||yesterday).replace(/'/g,"''")}') AS date,
  '${(r.channel||'').replace(/'/g,"''")}' AS channel,
  '${String(r.campaign_id||'').replace(/'/g,"''")}' AS campaign_id,
  '${String(r.campaign_name||'').replace(/'/g,"''")}' AS campaign_name,
  ${r.impressions||0} AS impressions,
  ${r.clicks||0} AS clicks,
  ${Number(r.spend||0).toFixed(6)} AS spend,
  ${r.conversions||0} AS conversions
)`).join(',\n');
  const sql = `MERGE \`${proj}.${ds}.campaigns_daily\` AS T
USING (SELECT * FROM UNNEST([${vals}])) AS S
ON T.date=S.date AND T.channel=S.channel AND T.campaign_id=S.campaign_id
WHEN MATCHED THEN UPDATE SET
  campaign_name=S.campaign_name, impressions=S.impressions,
  clicks=S.clicks, spend=S.spend, conversions=S.conversions,
  updated_at=CURRENT_TIMESTAMP()
WHEN NOT MATCHED THEN INSERT
  (date,channel,campaign_id,campaign_name,impressions,clicks,spend,conversions,created_at,updated_at)
VALUES(S.date,S.channel,S.campaign_id,S.campaign_name,S.impressions,S.clicks,S.spend,S.conversions,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP())`;
  results.push({ json: { channel: rows[0]?.channel || mapNode, sql } });
}

