// Contacts arrive as individual rows - aggregate to daily counts first
const hsRaw = $('Map � HubSpot').all().map(i => i.json);
if (hsRaw.length) {
  const agg = {};
  for (const r of hsRaw) {
    const date = (r.createdate || yesterday).slice(0,10);
    const camp = String(r.lead_utm_campaign||'').replace(/'/g,"''");
    const key  = date + '__' + camp;
    if (!agg[key]) agg[key] = { date, lead_utm_campaign: camp, leads_total: 0, leads_qualified: 0, leads_disqualified: 0 };
    agg[key].leads_total++;
    const st = (r.lead_status||'').toLowerCase();
    if (['sql','mql','qualified','sales qualified lead'].includes(st)) agg[key].leads_qualified++;
    if (['disqualified','junk','unqualified'].includes(st)) agg[key].leads_disqualified++;
  }
  const rows = Object.values(agg);
  const vals = rows.map(r => `STRUCT(
  DATE('${r.date}') AS date,
  '${r.lead_utm_campaign}' AS lead_utm_campaign,
  ${r.leads_total} AS leads_total,
  ${r.leads_qualified} AS leads_qualified,
  ${r.leads_disqualified} AS leads_disqualified
)`).join(',\n');
  const sql = `MERGE \`${proj}.${ds}.hubspot_leads_module_daily\` AS T
USING (SELECT * FROM UNNEST([${vals}])) AS S
ON T.date=S.date AND T.lead_utm_campaign=S.lead_utm_campaign
WHEN MATCHED THEN UPDATE SET
  leads_total=S.leads_total, leads_qualified=S.leads_qualified,
  leads_disqualified=S.leads_disqualified, updated_at=CURRENT_TIMESTAMP()
WHEN NOT MATCHED THEN INSERT
  (date,lead_utm_campaign,leads_total,leads_qualified,leads_disqualified,created_at,updated_at)
VALUES(S.date,S.lead_utm_campaign,S.leads_total,S.leads_qualified,S.leads_disqualified,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP())`;
  results.push({ json: { channel: 'hubspot', sql } });
}

return results;

const kpis = $('Query KPIs').all().map(i => i.json);
const flags = [];
const today = new Date().toISOString().slice(0, 10);

for (const row of kpis) {
  const { channel, roas, cpql, cpl, qual_pct, spend, leads } = row;
  if (!spend || spend < 5) continue; // skip channels with tiny spend

  // ROAS < 1x ? 3-factor check (Sub-Flow A)
  if (roas !== null && roas < 1.0) {
    flags.push({ flag_type: 'roas', channel, roas, cpql: cpql||0,
                 qual_rate_pct: qual_pct||0, leads_total: leads||0,
                 prior_leads_total: leads||0, spend, date: today });
  }

  // CPQL > $60 (above scale target) ? Sub-Flow C
  if (cpql !== null && cpql > 60 && (leads||0) >= 3) {
    flags.push({ flag_type: 'cpql', channel, cpql, cpl: cpl||0,
                 qual_rate_pct: qual_pct||0, leads, spend, date: today });
  }

  // CPL > $25 (above scale target) ? Sub-Flow B
  if (cpl !== null && cpl > 25 && (leads||0) >= 3) {
    flags.push({ flag_type: 'cpl', channel, cpl, leads, spend, date: today });
  }

  // Qual rate < 45% ? Sub-Flow D
  if (qual_pct !== null && qual_pct < 45 && (leads||0) >= 5) {
    flags.push({ flag_type: 'qual', channel, qual_rate_pct: qual_pct,
                 cpql: cpql||0, leads, spend, date: today });
  }
}

if (flags.length === 0) {
  return [{ json: { flag_type: 'green',
                    message: 'ALL SYSTEMS GREEN - no KPI flags today',
                    date: today } }];
}

console.log(`KPI Evaluator: ${flags.length} flag(s) found`);
return flags.map(f => ({ json: f }));

